.sig-dark-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid rgba(210,219,222,0.16);
  border-radius: 14px;
  background: linear-gradient(145deg, #0f1416, rgba(239,242,241,0.055));
  color: #eff2f1;
  box-shadow: 0 28px 78px rgba(0,0,0,0.38);
  font-family: Inter, ui-sans-serif, system-ui, sans-serif;
}
.sig-dark-hero::before { content: ""; position: absolute; inset: 0; background: linear-gradient(90deg, rgba(174,189,197,0.10) 1px, transparent 1px), linear-gradient(0deg, rgba(174,189,197,0.06) 1px, transparent 1px); background-size: 36px 36px; opacity: 0.78; pointer-events: none; }
.sig-dark-hero > * { position: relative; z-index: 1; }
.sig-dark-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-dark-hero .kicker { width: fit-content; border: 1px solid rgba(210,219,222,0.16); border-radius: 999px; padding: 6px 10px; color: #aebdc5; background: rgba(239,242,241,0.055); font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-dark-hero h1 { margin: 0; max-width: 620px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-dark-hero p { margin: 0; max-width: 560px; color: #8c989a; font-size: 15px; line-height: 1.78; }
.sig-dark-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-dark-hero button { height: 40px; padding: 0 16px; border-radius: calc(14px / 2 + 4px); border: 1px solid rgba(210,219,222,0.16); font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-dark-hero .primary { background: #aebdc5; color: #0f1416; border-color: #aebdc5; }
.sig-dark-hero .secondary { background: transparent; color: #eff2f1; }
.sig-dark-hero button:hover { transform: translateY(-1px); border-color: #aebdc5; }
.sig-dark-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid rgba(210,219,222,0.16); border-radius: calc(14px - 2px); background: rgba(239,242,241,0.055); backdrop-filter: blur(18px) saturate(140%); }
.sig-dark-hero .artifact h2 { margin: 0; font-size: 13px; color: #aebdc5; text-transform: uppercase; letter-spacing: 0; }
.sig-dark-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-dark-hero .metric { padding: 14px; border: 1px solid rgba(210,219,222,0.16); border-radius: calc(14px - 4px); background: color-mix(in srgb, #0f1416 76%, transparent); }
.sig-dark-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-dark-hero .metric span { display: block; margin-top: 6px; color: #8c989a; font-size: 11px; }
.sig-dark-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #aebdc5, #f2c673); }
@media (max-width: 780px) { .sig-dark-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-dark-card { width: min(100%, 390px); padding: 22px; border: 1px solid rgba(210,219,222,0.16); border-radius: 14px; background: #0f1416; color: #eff2f1; box-shadow: 0 28px 78px rgba(0,0,0,0.38); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-dark-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-dark-card .label { color: #aebdc5; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-dark-card .pill { border: 1px solid rgba(210,219,222,0.16); border-radius: 999px; padding: 5px 9px; color: #8c989a; background: rgba(239,242,241,0.055); font-size: 11px; }
.sig-dark-card h3 { margin: 0 0 10px; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-dark-card p { margin: 0; color: #8c989a; font-size: 13px; line-height: 1.7; }
.sig-dark-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid rgba(210,219,222,0.16); }
.sig-dark-card .strip strong { font-variant-numeric: tabular-nums; color: #eff2f1; }
.sig-dark-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(14px - 4px); background: #aebdc5; color: #0f1416; font-weight: 900; }

.sig-dark-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid rgba(210,219,222,0.16); border-radius: 14px; background: #0f1416; color: #eff2f1; box-shadow: 0 28px 78px rgba(0,0,0,0.38); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-dark-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: Inter, ui-sans-serif, system-ui, sans-serif; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-dark-nav .mark { width: 30px; height: 30px; border-radius: calc(14px - 4px); background: linear-gradient(135deg, #aebdc5, #f2c673); box-shadow: inset 0 0 0 1px rgba(210,219,222,0.16); }
.sig-dark-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-dark-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(14px - 6px); color: #8c989a; text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-dark-nav a:hover, .sig-dark-nav a.active { color: #eff2f1; background: rgba(239,242,241,0.055); }
.sig-dark-nav button { height: 34px; padding: 0 13px; border-radius: calc(14px - 6px); border: 1px solid #aebdc5; background: #aebdc5; color: #0f1416; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-dark-nav { align-items: stretch; flex-direction: column; } }

.sig-dark-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid rgba(210,219,222,0.16); border-radius: 14px; background: #0f1416; color: #eff2f1; box-shadow: 0 28px 78px rgba(0,0,0,0.38); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-dark-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #eff2f1; }
.sig-dark-form small { color: #8c989a; font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-dark-form .row { display: flex; gap: 10px; }
.sig-dark-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(14px - 6px); border: 1px solid rgba(210,219,222,0.16); background: rgba(239,242,241,0.055); color: #eff2f1; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-dark-form input:focus { border-color: #aebdc5; box-shadow: 0 0 0 3px color-mix(in srgb, #aebdc5 18%, transparent); }
.sig-dark-form button { height: 42px; padding: 0 14px; border-radius: calc(14px - 6px); border: 1px solid #aebdc5; background: #aebdc5; color: #0f1416; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-dark-form .row { flex-direction: column; } }

.sig-dark-table { width: min(100%, 780px); overflow: hidden; border: 1px solid rgba(210,219,222,0.16); border-radius: 14px; background: #0f1416; color: #eff2f1; box-shadow: 0 28px 78px rgba(0,0,0,0.38); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-dark-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-dark-table th, .sig-dark-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid rgba(210,219,222,0.16); }
.sig-dark-table th { color: #8c989a; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: rgba(239,242,241,0.055); }
.sig-dark-table td { color: #eff2f1; }
.sig-dark-table tr:last-child td { border-bottom: 0; }
.sig-dark-table tbody tr:hover td { background: rgba(239,242,241,0.055); }
.sig-dark-table .mono { font-variant-numeric: tabular-nums; }
.sig-dark-table .status { display: inline-flex; align-items: center; gap: 6px; color: #aebdc5; font-weight: 800; }
.sig-dark-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #aebdc5; }

.bg-void {
  min-height: 100vh;
  background: radial-gradient(ellipse at 50% 30%, #0f0a1a 0%, #09090b 70%);
}

.card-metric {
  padding: 20px 24px;
  border-radius: 12px;
  background: #111113;
  border: 0.5px solid #27272a;
  width: 220px;
}
.card-metric .label {
  font-family: 'Inter', system-ui;
  font-size: 12px;
  font-weight: 500;
  color: #71717a;
  margin-bottom: 8px;
}
.card-metric .value {
  font-family: 'Inter', system-ui;
  font-size: 32px;
  font-weight: 700;
  color: #fafafa;
  font-variant-numeric: tabular-nums;
  letter-spacing: -0.5px;
  margin-bottom: 6px;
}
.card-metric .change {
  font-family: 'Inter', system-ui;
  font-size: 12px;
  font-weight: 500;
}
.card-metric .change.up { color: #22c55e; }
.card-metric .change.down { color: #ef4444; }

.hero-codex-void {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: #030712;
  padding: 40px 24px;
  text-align: center;
}
.hero-codex-void h1 {
  font-family: 'Inter', system-ui;
  font-size: clamp(56px, 12vw, 120px);
  font-weight: 900;
  color: #e4e4e7;
  letter-spacing: -0.04em;
  line-height: 1;
  margin: 0 0 24px;
}
.hero-codex-void p {
  font-family: 'Inter', system-ui;
  font-size: 15px;
  color: #71717a;
  margin: 0;
  max-width: 420px;
  line-height: 1.6;
}

.form-underline {
  position: relative;
  padding-top: 18px;
}
.form-underline label {
  position: absolute;
  top: 0;
  left: 0;
  font-family: 'Inter', system-ui;
  font-size: 12px;
  font-weight: 500;
  color: #71717a;
}
.form-underline input {
  width: 100%;
  padding: 8px 0;
  font-family: 'Inter', system-ui;
  font-size: 15px;
  color: #fafafa;
  background: none;
  border: none;
  border-bottom: 1px solid #27272a;
  outline: none;
  transition: border-color 0.2s;
}
.form-underline input:focus { border-color: #60a5fa; }
.form-underline .focus-line {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 1.5px;
  background: #60a5fa;
  transform: scaleX(0);
  transition: transform 0.3s cubic-bezier(0.16, 1, 0.3, 1);
}
.form-underline input:focus ~ .focus-line { transform: scaleX(1); }

.modal-clean-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.6);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
}
.modal-clean {
  width: min(90%, 420px);
  border-radius: 12px;
  background: #111113;
  border: 0.5px solid #27272a;
  padding: 24px;
  color: #fafafa;
}
.modal-clean h3 {
  font-family: 'Inter', system-ui;
  font-size: 16px;
  font-weight: 600;
  margin: 0 0 8px;
}
.modal-clean p {
  font-family: 'Inter', system-ui;
  font-size: 14px;
  color: #a1a1aa;
  line-height: 1.6;
  margin: 0 0 20px;
}
.modal-clean .actions { display: flex; justify-content: flex-end; gap: 8px; }
.modal-clean .btn-ghost {
  padding: 9px 16px;
  border-radius: 8px;
  background: transparent;
  border: 0.5px solid #27272a;
  color: #e4e4e7;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.15s;
}
.modal-clean .btn-ghost:hover { background: rgba(255,255,255,0.04); }
.modal-clean .btn-primary {
  padding: 9px 16px;
  border-radius: 8px;
  background: #fafafa;
  color: #09090b;
  border: none;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  transition: opacity 0.15s;
}
.modal-clean .btn-primary:hover { opacity: 0.9; }

.footer-micro {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 24px;
  border-top: 0.5px solid #27272a;
  font-family: 'Inter', system-ui;
  font-size: 12px;
  color: #52525b;
}
.footer-micro .links { display: flex; gap: 16px; }
.footer-micro a { color: #52525b; text-decoration: none; transition: color 0.15s; }
.footer-micro a:hover { color: #a1a1aa; }

.table-linear {
  width: 100%;
  border-collapse: collapse;
  font-family: 'Inter', system-ui;
}
.table-linear th {
  padding: 10px 16px;
  text-align: left;
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  color: #52525b;
  border-bottom: 0.5px solid #1a1a1a;
}
.table-linear td {
  padding: 10px 16px;
  font-size: 13px;
  color: #d4d4d8;
  border-bottom: 0.5px solid #1a1a1a;
}
.table-linear tr:hover td { background: rgba(255,255,255,0.02); }
.table-linear tr:last-child td { border-bottom: none; }

.badge-dot {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-family: 'Inter', system-ui;
  font-size: 12px;
  font-weight: 500;
  color: #a1a1aa;
}
.badge-dot .dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  flex-shrink: 0;
}
.badge-dot.active .dot { background: #22c55e; }
.badge-dot.active { color: #22c55e; }
.badge-dot.warning .dot { background: #eab308; }
.badge-dot.warning { color: #eab308; }
.badge-dot.error .dot { background: #ef4444; }
.badge-dot.error { color: #ef4444; }
.badge-dot.neutral .dot { background: #52525b; }

.anim-focus-in {
  animation: focus-in 0.5s cubic-bezier(0.16, 1, 0.3, 1) both;
}
@keyframes focus-in {
  from {
    opacity: 0;
    filter: blur(8px);
    transform: scale(0.98);
  }
  to {
    opacity: 1;
    filter: blur(0);
    transform: scale(1);
  }
}

.nav-icon-rail {
  width: 48px;
  height: 100vh;
  background: #09090b;
  border-right: 0.5px solid #1a1a1a;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 12px 0;
  gap: 4px;
}
.nav-icon-rail .item {
  width: 36px;
  height: 36px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  color: #52525b;
  cursor: pointer;
  position: relative;
  transition: all 0.15s;
}
.nav-icon-rail .item:hover { color: #a1a1aa; background: rgba(255,255,255,0.03); }
.nav-icon-rail .item.active { color: #fafafa; }
.nav-icon-rail .item.active::before {
  content: '';
  position: absolute;
  left: -6px;
  top: 25%;
  bottom: 25%;
  width: 2px;
  border-radius: 1px;
  background: #fafafa;
}

.nav-breadcrumb-slash {
  display: flex;
  align-items: center;
  gap: 8px;
  font-family: 'Inter', system-ui;
  font-size: 13px;
}
.nav-breadcrumb-slash a {
  color: #71717a;
  text-decoration: none;
  transition: color 0.15s;
}
.nav-breadcrumb-slash a:hover { color: #a1a1aa; }
.nav-breadcrumb-slash .sep { color: #3f3f46; }
.nav-breadcrumb-slash .current { color: #fafafa; font-weight: 500; }

.form-select-trigger {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 9px 12px;
  border-radius: 8px;
  background: #111113;
  border: 0.5px solid #27272a;
  font-family: 'Inter', system-ui;
  font-size: 13px;
  color: #d4d4d8;
  cursor: pointer;
  min-width: 180px;
  transition: border-color 0.15s;
}
.form-select-trigger:hover { border-color: #3f3f46; }
.form-select-trigger .chevron { color: #52525b; font-size: 12px; }
.form-select-panel {
  margin-top: 4px;
  border-radius: 8px;
  background: #111113;
  border: 0.5px solid #27272a;
  padding: 4px;
  box-shadow: 0 8px 24px rgba(0,0,0,0.3);
}
.form-select-panel .option {
  padding: 8px 10px;
  border-radius: 5px;
  font-family: 'Inter', system-ui;
  font-size: 13px;
  color: #d4d4d8;
  cursor: pointer;
  transition: background 0.1s;
}
.form-select-panel .option:hover { background: rgba(255,255,255,0.04); color: #fafafa; }

.layout-dash-bento {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 1px;
  background: #1a1a1a;
  border-radius: 12px;
  overflow: hidden;
  border: 0.5px solid #1a1a1a;
}
.layout-dash-bento .cell {
  background: #09090b;
  padding: 20px;
  min-height: 120px;
}
.layout-dash-bento .cell.wide { grid-column: span 2; }
.layout-dash-bento .cell.tall { grid-row: span 2; }

.layout-sidebar-app {
  display: grid;
  grid-template-columns: 240px 1fr;
  height: 100vh;
  background: #09090b;
  color: #fafafa;
}
.layout-sidebar-app .sidebar {
  border-right: 0.5px solid #1a1a1a;
  display: flex;
  flex-direction: column;
}
.layout-sidebar-app .sidebar .logo {
  height: 56px;
  display: flex;
  align-items: center;
  padding: 0 16px;
  font-size: 14px;
  font-weight: 600;
  font-family: 'Inter', system-ui;
  border-bottom: 0.5px solid #1a1a1a;
}
.layout-sidebar-app .sidebar nav { padding: 12px 8px; flex: 1; }
.layout-sidebar-app .sidebar nav a {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: 6px;
  font-size: 13px;
  color: #71717a;
  text-decoration: none;
  transition: all 0.1s;
}
.layout-sidebar-app .sidebar nav a:hover { color: #a1a1aa; background: rgba(255,255,255,0.02); }
.layout-sidebar-app .sidebar nav a.active { color: #fafafa; background: rgba(255,255,255,0.04); }
.layout-sidebar-app .content { padding: 32px; overflow-y: auto; }

.modal-toast-stack {
  position: fixed;
  bottom: 16px;
  right: 16px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  z-index: 9999;
  width: 340px;
}
.modal-toast-item {
  padding: 14px 16px;
  border-radius: 10px;
  background: #111113;
  border: 0.5px solid #27272a;
  box-shadow: 0 4px 16px rgba(0,0,0,0.3);
  animation: toast-enter 0.3s cubic-bezier(0.16, 1, 0.3, 1);
  position: relative;
  overflow: hidden;
}
.modal-toast-item::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 3px;
}
.modal-toast-item.success::before { background: #22c55e; }
.modal-toast-item.error::before { background: #ef4444; }
.modal-toast-item .title { font-family: 'Inter', system-ui; font-size: 14px; font-weight: 500; color: #fafafa; margin-bottom: 2px; }
.modal-toast-item .desc { font-family: 'Inter', system-ui; font-size: 13px; color: #71717a; }
@keyframes toast-enter {
  from { opacity: 0; transform: translateX(16px) scale(0.96); }
  to { opacity: 1; transform: translateX(0) scale(1); }
}

.footer-stripe {
  background: #09090b;
  color: #fafafa;
  padding: 64px 48px 32px;
  font-family: 'Inter', system-ui;
}
.footer-stripe .grid {
  display: grid;
  grid-template-columns: 1.5fr repeat(4, 1fr);
  gap: 40px;
  margin-bottom: 48px;
}
.footer-stripe .brand-col .logo { font-size: 16px; font-weight: 700; margin-bottom: 8px; }
.footer-stripe .brand-col .desc { font-size: 13px; color: #52525b; line-height: 1.5; }
.footer-stripe .link-col h5 {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #52525b;
  margin: 0 0 14px;
}
.footer-stripe .link-col a {
  display: block;
  font-size: 13px;
  color: #71717a;
  text-decoration: none;
  margin-bottom: 10px;
  transition: color 0.15s;
}
.footer-stripe .link-col a:hover { color: #a1a1aa; }
.footer-stripe .bottom {
  border-top: 0.5px solid #1a1a1a;
  padding-top: 20px;
  font-size: 12px;
  color: #3f3f46;
}

.table-issues {
  width: 100%;
  font-family: 'Inter', system-ui;
}
.table-issues .row {
  display: grid;
  grid-template-columns: 24px 1fr auto auto auto;
  align-items: center;
  gap: 12px;
  padding: 0 16px;
  height: 40px;
  border-radius: 6px;
  transition: background 0.1s;
  cursor: pointer;
}
.table-issues .row:hover { background: rgba(255,255,255,0.02); }
.table-issues .status { width: 14px; height: 14px; border-radius: 50%; border: 1.5px solid #52525b; }
.table-issues .status.done { background: #22c55e; border-color: #22c55e; }
.table-issues .status.progress { border-color: #eab308; border-right-color: transparent; }
.table-issues .title { font-size: 14px; font-weight: 500; color: #e4e4e7; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.table-issues .label {
  padding: 2px 8px;
  border-radius: 50px;
  font-size: 11px;
  font-weight: 500;
  background: rgba(96,165,250,0.1);
  color: #60a5fa;
}
.table-issues .priority { font-size: 14px; color: #52525b; }
.table-issues .avatar { width: 20px; height: 20px; border-radius: 50%; background: #27272a; }

.badge-kbd {
  display: inline-flex;
  align-items: center;
  gap: 3px;
}
.badge-kbd kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 20px;
  height: 20px;
  padding: 0 5px;
  border-radius: 4px;
  background: #1a1a1a;
  border: 0.5px solid #27272a;
  border-bottom-width: 1.5px;
  font-family: system-ui, -apple-system;
  font-size: 11px;
  color: #a1a1aa;
}
.badge-kbd .plus { color: #3f3f46; font-size: 10px; margin: 0 1px; }

.badge-chip {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 50px;
  font-family: 'Inter', system-ui;
  font-size: 11px;
  font-weight: 500;
}
.badge-chip.green { background: rgba(34,197,94,0.08); color: #22c55e; }
.badge-chip.yellow { background: rgba(234,179,8,0.08); color: #eab308; }
.badge-chip.red { background: rgba(239,68,68,0.08); color: #ef4444; }
.badge-chip.blue { background: rgba(96,165,250,0.08); color: #60a5fa; }
.badge-chip.purple { background: rgba(168,85,247,0.08); color: #a855f7; }
.badge-chip.gray { background: rgba(161,161,170,0.08); color: #71717a; }

.anim-page-enter {
  animation: page-in 0.3s cubic-bezier(0.16, 1, 0.3, 1) both;
}
.anim-page-exit {
  animation: page-out 0.2s cubic-bezier(0.4, 0, 1, 1) both;
}
@keyframes page-in {
  from { opacity: 0; transform: translateY(8px) scale(0.99); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}
@keyframes page-out {
  from { opacity: 1; transform: translateY(0); }
  to { opacity: 0; transform: translateY(-4px); }
}

.anim-skeleton {
  background: #1a1a1a;
  border-radius: 6px;
  animation: skeleton-pulse 1.5s ease-in-out infinite;
}
@keyframes skeleton-pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

@property --num {
  syntax: '<integer>';
  initial-value: 0;
  inherits: false;
}
.anim-number-tick {
  animation: tick-up 2s ease-out forwards;
  counter-reset: num var(--num);
  font-family: 'Inter', system-ui;
  font-variant-numeric: tabular-nums;
}
.anim-number-tick::after {
  content: counter(num);
}
@keyframes tick-up {
  to { --num: var(--target, 100); }
}
